import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.util.concurrent.locks.Lock;
import java.util.concurrent.locks.ReentrantLock;

public class BankingService {
    private final Lock lock = new ReentrantLock();

    public void processTransaction(Connection connection, int accountId, double transactionAmount) throws SQLException {
        lock.lock();
        try {
            connection.setAutoCommit(false);

            double currentBalance = getAccountBalance(connection, accountId);
            if (currentBalance >= transactionAmount) {
                double newBalance = currentBalance - transactionAmount;
                updateAccountBalance(connection, accountId, newBalance);
                connection.commit();
            } else {
                throw new SQLException("Insufficient funds");
            }
        } catch (SQLException e) {
            connection.rollback();
            throw e;
        } finally {
            connection.setAutoCommit(true);
            lock.unlock();
        }
    }

    private double getAccountBalance(Connection connection, int accountId) throws SQLException {
        String query = "SELECT balance FROM accounts WHERE account_id = ?";
        try (PreparedStatement stmt = connection.prepareStatement(query)) {
            stmt.setInt(1, accountId);
            try (ResultSet rs = stmt.executeQuery()) {
                if (rs.next()) {
                    return rs.getDouble("balance");
                } else {
                    throw new SQLException("Account not found");
                }
            }
        }
    }

    private void updateAccountBalance(Connection connection, int accountId, double newBalance) throws SQLException {
        String update = "UPDATE accounts SET balance = ? WHERE account_id = ?";
        try (PreparedStatement stmt = connection.prepareStatement(update)) {
            stmt.setDouble(1, newBalance);
            stmt.setInt(2, accountId);
            stmt.executeUpdate();
        }
    }
}